var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이, 이봐! 뉴 오하이오가 떠나 버렸다고! 설마 도망친 거냐?!!","JPN":"お、おい！　ニューオハイオが出港したぞ！\\nまさか逃げ出したのか！？","ENG":"H-hey! The New Ohio took off! Did she run away?!","TWN":"喂！新俄亥俄要離開了！難道他們要逃跑？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"말 조심해. 사령관님께서는 아군을 구원하기 위해 홀로 차원 폭풍 속으로 돌입하셨다.","JPN":"口を慎め。\\n司令官は味方を助けるために単独で次元の暴風の中に突入したんだ。","ENG":"Watch your mouth. The Commander has headed for the dimensional storm alone to save those in there.","TWN":"說話注意點。司令官是為了救援友軍，要一個人衝進次元風暴內部。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 분을 모욕하지 마라.","JPN":"あの方を侮辱するんじゃない。","ENG":"Stop insulting her.","TWN":"不准侮辱司令官。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"그럼 더 나쁜 거잖아!","JPN":"そりゃあ、さらに貧乏くじをひいたようなもんじゃないか！","ENG":"That's worse!","TWN":"那不是更糟嗎！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"차라리 도망쳤으면 지원군을 불러 올 가능성이라도 있지!","JPN":"もし逃げたなら援軍を連れてくる可能性があったのに！","ENG":"If she ran away, there would have been a possibility of her sending help our way.","TWN":"還不如直接逃跑呢，那樣說不定還有機會叫援軍！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"차원 폭풍이 점점 더 격렬해지고 있다고! 저기서 살아 나올 사람이 있을 것 같아?","JPN":"次元の暴風がさらに激しさを増しているんだ！\\nあの中から生還できる人間がいると思うか？","ENG":"The dimensional storm is becoming more threatening by the minute! There's no way she could come out of there alive!","TWN":"次元風暴越來越猛烈了啊！那裡像是能有人活著出來的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"제, 제기랄! 나라도 도망쳐야겠어!","JPN":"ク、クソ！　俺だけでも逃げなきゃ！","ENG":"Gah! I'm just going to run!","TWN":"可、可惡！我還是逃走吧·！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하아...... 저런 것도 아군이라고 지켜야 하다니 어린 시절의 맹세에 조금 회의가 드는군.","JPN":"はあ……味方だからってあんなのも守らなきゃならないなんて、\\n子ども時代の誓いが揺らぎそうだ。","ENG":"*Sigh* I can't believe I have to protect this coward. Maybe I shouldn't have made that pledge when I was young.","TWN":"唉……那種玩意兒也能叫友軍，我們竟然還得保護他們，我有點懷疑起自己小時候的誓言了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 소장님을 실망시켜 드릴 순 없지.","JPN":"けど、少将を失望させるわけにはいかないからな。","ENG":"But I can't disappoint the Major General.","TWN":"但不能讓少將大人失望。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아아, 마이크 테스트. 다들 잘 들리나?","JPN":"チェック・ワン・ツー、マイクテスト。みんな聞こえるか？","ENG":"Ah, ah. Mic test. Everyone, can you hear me?","TWN":"啊——啊——，麥克風測試。大家都能聽到嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나는 안토노프 소장님으로부터 임시로 지휘권을 이양 받은 제이크 워커 소령이다.","JPN":"俺はアントノフ少将から指揮代行を任せられたジェイク・ウォーカー少佐だ。","ENG":"I'm Major Jake Walker, and I'll be temporarily in charge of you until Major General Antonov returns.","TWN":"我是臨時從安東諾夫少將大人那裡，接任指揮權的傑克·沃克少校。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"임시 지휘? 소령님이?","JPN":"指揮代行？　少佐が？","ENG":"The Major is in charge of us?","TWN":"臨時指揮？少校？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어이, 버터맨! 너 지휘가 뭔지는 알고 있는 거야?","JPN":"ちょっと、バターマン！　あなた、指揮が何なのかはわかってるの？","ENG":"Hey, Sleazeball. Do you even know how to command?","TWN":"喂，小白臉！你知道什麼是指揮嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"격려 고맙군, 사랑스런 전우 여러분.","JPN":"激励の言葉をありがとう、愛する戦友の皆さん。","ENG":"Thank you for your encouragement, my dear comrades.","TWN":"感謝大家的鼓勵，親愛的戰友們。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 우리에게 가장 중요한 건 등대가 손상되지 않도록 지키는 일이다.","JPN":"とにかく我々の最重要ミッションは、灯台が損傷しないように守り抜くことだ。","ENG":"Anyway, our priority at this moment is the safety of the Lighthouse.","TWN":"總之，我們現在最重要的事情，就是保護燈塔不受損傷。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"다들 전열을 형성해서 최대한 방어에 집중하도록.","JPN":"全員戦列を整えて、最大限防御に集中するように。","ENG":"Everyone, stand in formation around the Lighthouse and focus on defending it.","TWN":"請各位排好列隊，盡最大努力進行集中防禦。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"적의 예봉을 꺾고 정면에서 깨부수는 역할은 내가 맡는다.","JPN":"敵の鋭鋒を破り正面から打ち砕くのは俺が担当する。","ENG":"I'll stay on the front line to bear the brunt of enemies.","TWN":"而重挫敵人銳氣，從正面粉碎它們的任務就交給我了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};